%%%%%%%%%% Function vrnOpnBin2.m %%%%%%%%%%% Varian Open file and Bin data%% Kei Nakamura% Created on Sunday, March 13th 2006.% function img = vrnOpnBin2(num,name);% opne the binary file from Varian Spectromrter% bins into 2by2,% and save a binned image on 'new' directory as the same name.% Only for images from a high resolution flea CCD.function [img imgB] = vrnOpnBin2(numS,namC)  %function headername = strcat(num2str(numS),'cam',num2str(namC));fid = fopen(name,'r');  % open fileimg = fread(fid,[1024 inf],'int16');fclose(fid);imgB = img(1:2:end,1:2:end);imgB = imgB + img(1:2:end,2:2:end);imgB = imgB + img(2:2:end,1:2:end);imgB = imgB + img(2:2:end,2:2:end); cd('new');fid = fopen(name,'wb');  % open filefwrite(fid,imgB,'int16');fclose(fid);cd('..');
